+// Torch flame animation frames (simple flicker offsets)
+const TORCH_FLAME_FRAMES = [
+  { dx: 0, dy: 0, alpha: 1 },
+  { dx: 1, dy: -1, alpha: 0.85 },
+  { dx: -1, dy: 1, alpha: 0.9 },
+  { dx: 0, dy: -1, alpha: 0.8 },
+  { dx: 1, dy: 0, alpha: 0.95 },
+];
+
+function drawTorch(ctx: CanvasRenderingContext2D, x: number, y: number, frame: number) {
+  // Base torch handle and holder
+  ctx.fillStyle = '#4a4a58'; ctx.fillRect(x + 1, y + 10, 6, 4); ctx.fillRect(x + 5, y + 8, 3, 8);
+  ctx.fillStyle = '#4a2810'; ctx.fillRect(x + 2, y + 4, 4, 14);
+  ctx.fillStyle = '#5c3418'; ctx.fillRect(x + 3, y + 5, 2, 12);
+
+  // Animated flame
+  const f = TORCH_FLAME_FRAMES[frame % TORCH_FLAME_FRAMES.length];
+  const flameX = x + 4 + f.dx;
+  const flameY = y - 5 + f.dy;
+
+  // Flame core
+  ctx.fillStyle = `rgba(255, 180, 60, ${f.alpha})`;
+  ctx.beginPath();
+  ctx.ellipse(flameX, flameY, 4, 8, 0, 0, Math.PI * 2);
+  ctx.fill();
+
+  // Inner bright flame
+  ctx.fillStyle = `rgba(255, 220, 100, ${f.alpha * 0.6})`;
+  ctx.beginPath();
+  ctx.ellipse(flameX, flameY - 2, 2, 4, 0, 0, Math.PI * 2);
+  ctx.fill();
+
+  // Glow radial gradient
+  const glowRadius = 24 + Math.sin(frame * 0.15) * 4;
+  const grd = ctx.createRadialGradient(flameX, flameY + 2, 0, flameX, flameY + 2, glowRadius);
+  grd.addColorStop(0, `rgba(255, 180, 60, 0.12)`);
+  grd.addColorStop(1, `rgba(255, 180, 60, 0)`);
+  ctx.fillStyle = grd;
+  ctx.fillRect(flameX - glowRadius, flameY - glowRadius, glowRadius * 2, glowRadius * 2);
+}
+
+function drawRoomLighting(ctx: CanvasRenderingContext2D, type: CharacterType, x: number, y: number, w: number, h: number) {
+  // Base corner ambient lights
+  const cs = Math.max(w, h) * 0.4;
+  for (const [cx, cy] of [[x, y], [x + w, y], [x, y + h], [x + w, y + h]] as [number, number][]) {
+    const g = ctx.createRadialGradient(cx, cy, 0, cx, cy, cs);
+    g.addColorStop(0, 'rgba(0,0,0,0.2)'); g.addColorStop(1, 'rgba(0,0,0,0)');
+    ctx.fillStyle = g;
+    ctx.fillRect(Math.max(x, cx - cs), Math.max(y, cy - cs), cs, cs);
+  }
+
+  // Additional subtle glow for healer and king rooms
+  if (type === 'healer' || type === 'king') {
+    const g = ctx.createRadialGradient(x + w / 2, y + h * 0.5, 0, x + w / 2, y + h * 0.5, w * 0.45);
+    g.addColorStop(0, 'rgba(255, 200, 100, 0.04)'); g.addColorStop(1, 'rgba(255, 200, 100, 0)');
+    ctx.fillStyle = g; ctx.fillRect(x, y, w, h);
+  }
+
+  // Torch light sources per room type with positions and radius
+  const torchLights: { x: number; y: number; radius: number }[] = [];
+  switch (type) {
+    case 'king':
+      torchLights.push({ x: x + w * 0.02 + 4, y: y + h * 0.15 + 6, radius: 60 });
+      torchLights.push({ x: x + w * 0.92 + 4, y: y + h * 0.15 + 6, radius: 60 });
+      break;
+    case 'nobility':
+      torchLights.push({ x: x + w * 0.02 + 4, y: y + h * 0.12 + 6, radius: 50 });
+      break;
+    case 'knight':
+      torchLights.push({ x: x + w * 0.5 + 4, y: y + h * 0.06 + 6, radius: 50 });
+      break;
+    case 'squire':
+      torchLights.push({ x: x + w * 0.88 + 4, y: y + h * 0.1 + 6, radius: 50 });
+      break;
+    case 'sentinel':
+      torchLights.push({ x: x + w * 0.02 + 4, y: y + h * 0.28 + 6, radius: 50 });
+      torchLights.push({ x: x + w * 0.9 + 4, y: y + h * 0.28 + 6, radius: 50 });
+      break;
+    case 'scribe':
+      torchLights.push({ x: x + w * 0.08 + 4, y: y + h * 0.15 + 6, radius: 50 });
+      break;
+    case 'judge':
+      torchLights.push({ x: x + w * 0.08 + 4, y: y + h * 0.15 + 6, radius: 50 });
+      torchLights.push({ x: x + w * 0.85 + 4, y: y + h * 0.15 + 6, radius: 50 });
+      break;
+    case 'blacksmith':
+      torchLights.push({ x: x + w * 0.38 + 4, y: y + h * 0.06 + 6, radius: 50 });
+      break;
+  }
+
+  // Draw radial glow for each torch light
+  for (const light of torchLights) {
+    const grad = ctx.createRadialGradient(light.x, light.y, 0, light.x, light.y, light.radius);
+    grad.addColorStop(0, 'rgba(255, 180, 60, 0.3)');
+    grad.addColorStop(0.7, 'rgba(255, 180, 60, 0.1)');
+    grad.addColorStop(1, 'rgba(255, 180, 60, 0)');
+    ctx.fillStyle = grad;
+    ctx.fillRect(light.x - light.radius, light.y - light.radius, light.radius * 2, light.radius * 2);
+  }
+}
